This directly addresses the current missing verified data while avoiding the prior crash.",
  "commands": [
    {
      "keystrokes": "cat > /app/analyze_components.py <<'PY'
import urllib.request, urllib.parse, json, re, time, ssl
ctx=ssl.create_default_context()

def fetch(url, timeout=15, tries=3, max_bytes=None, headers=None):
    h={'User-Agent':'Mozilla/5.0','Accept':'application/json,text/html,*/*'}
    if headers: h.update(headers)
    last=None
    for i in range(tries):
        try:
            req=urllib.request.Request(url, headers=h)
            with urllib.request.urlopen(req, timeout=timeout, context=ctx) as r:
                data=r.read()
            return data[:max_bytes] if max_bytes else data
        except Exception as e:
            last=e
            time.sleep(0.5*(i+1))
    raise last

ids=[x.strip() for x in open('/app/pdb_ids.txt') if x.strip()]
idset=set(ids)

print('=== FPBASE MATCHES ===')
fp=json.load(open('/app/fpbase_full.json'))
rows=[]
for p in fp:
    seq=p.get('seq') or ''
    pdb=p.get('pdb') or []
    for st in p.get('states',[]):
        ex=st.get('ex_max'); em=st.get('em_max')
        if ex is not None and em is not None:
            rows.append((p.get('name'),p.get('slug'),p.get('uuid'),len(seq),ex,em,pdb,set(map(str.upper,pdb))&idset,seq))
rows.sort(key=lambda r:(r[3]==0, -(len(r[7])), r[4], r[5]))
print('donor candidates excitation 505 exact:')
for r in rows:
    if r[4]==505:
        print('DONOR', r[0], r[1], r[2], 'len', r[3], 'ex', r[4], 'em', r[5], 'pdb', r[6], 'matched', sorted(r[7]), 'seqprefix', r[8][:40])
print('acceptor candidates emission 610 exact:')
for r in rows:
    if r[5]==610:
        print('ACCEPTOR', r[0], r[1], r[2], 'len', r[3], 'ex', r[4], 'em', r[5], 'pdb', r[6], 'matched', sorted(r[7]), 'seqprefix', r[8][:40])
print('near donor ex 505 +/-5:')
for r in rows:
    if abs(r[4]-505)<=5:
        print('NEARDONOR', r[0], r[1], 'len', r[3], 'ex', r[4], 'em', r[5], 'pdb', r[6], 'matched', sorted(r[7]))
print('near acceptor em 610 +/-5:')
for r in rows:
    if abs(r[5]-610)<=5:
        print('NEARACCEPTOR', r[0], r[1], 'len', r[3], 'ex', r[4], 'em', r[5], 'pdb', r[6], 'matched', sorted(r[7]))

print('\\n=== PDB LIGANDS/BINDING SITES ===')
smiles_target='Nc3nc(OCc1ccccc1)c2nc[nH]c2n3'
lig_data={}; site_data={}
for pid in ids:
    for name,ep in [('ligands',f'https://www.ebi.ac.uk/pdbe/api/pdb/entry/ligands/{pid.lower()}'), ('binding_sites',f'https://www.ebi.ac.uk/pdbe/api/pdb/entry/binding_sites/{pid.lower()}')]:
        try:
            d=json.loads(fetch(ep, timeout=10, tries=2))
            txt=json.dumps(d).replace(' ','')
            match=smiles_target.replace(' ','') in txt
            low=txt.lower()
            hints=[]
            for kw in ['benzylguanine','benzyl','guanine','bgc','mtz','methotrexate','folate','folic','ampicillin','amp','ras','cyclophilin','snap','chymotrypsin','polymerase']:
                if kw in low:
                    hints.append(kw)
            if match or hints:
                print('INTEREST', pid, name, 'match', match, 'hints', hints, 'prefix', txt[:800])
            if name=='ligands' and d: lig_data[pid]=d
            elif name=='binding_sites' and d: site_data[pid]=d
        except Exception as e:
            print('ERR', pid, name, type(e).__name__, str(e)[:80])
    time.sleep(0.02)
open('/app/pdb_ligands.json','w').write(json.dumps(lig_data,indent=1))
open('/app/pdb_binding_sites.json','w').write(json.dumps(site_data,indent=1))

print('\\n=== RCSB SMILES SEARCH ===')
try:
    body=json.dumps({"query":{"type":"terminal","service":"chemical","parameters":{"value_type":"smiles","value":smiles_target,"match_type":"graph-relaxed-stereochemistry"}},"return_type":"entry","request_options":{"results_content_type":["experimental"]}}).encode()
    req=urllib.request.Request('https://search.rcsb.org/rcsbsearch/v2/query', data=body, headers={'User-Agent':'Mozilla/5.0','Content-Type':'application/json'})
    d=urllib.request.urlopen(req, timeout=15, context=ctx).read().decode('utf-8','replace')
    print('OK', d[:1200])
    open('/app/rcsb_smiles_search.txt','w').write(d)
except Exception as e:
    print('ERR RCSB', type(e).__name__, str(e)[:300])

print('\\n=== UNIPROT HER2 ===')
try:
    d=fetch('https://rest.uniprot.org/uniprotkb/P04626.fasta', timeout=12, tries=3).decode()
    open('/app/HER2.fasta','w').write(d)
    seq=''.join(line.strip() for line in d.splitlines() if not line.startswith('>'))
    print('HER2_SEQLEN', len(seq), 'PREFIX', seq[:100])
    open('/app/her2_seq.txt','w').write(seq)
except Exception as e:
    print('ERR HER2', type(e).__name__, str(e)[:300])

print('\\n=== PDB TITLES ===')
try:
    meta=json.load(open('/app/pdb_meta.json'))
    for pid in ids:
        print('PDBTITLE', pid, meta.get(pid,{}).get('title',''))
except Exception as e:
    print('ERR META', type(e).__name__, e)
